import{_ as t,o as i,c as a,ag as n}from"./chunks/framework.HG0H2VLS.js";const u=JSON.parse('{"title":"Spinner — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/components/Spinner/Spinner.figma-notes.md","filePath":"public/demos/src/components/Spinner/Spinner.figma-notes.md"}'),o={name:"public/demos/src/components/Spinner/Spinner.figma-notes.md"};function s(r,e,d,l,c,p){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="spinner-—-figma-notes" tabindex="-1">Spinner — Figma Notes <a class="header-anchor" href="#spinner-—-figma-notes" aria-label="Permalink to &quot;Spinner — Figma Notes&quot;">​</a></h1><p><strong>Status:</strong> Code-first (Flowbite-inspired). No Figma node yet — flag for designer to formalise. <strong>Tier:</strong> Component <strong>Files:</strong> <code>Spinner.css</code>, <code>Spinner.html</code>, <code>Spinner.figma-notes.md</code><em>(<code>Spinner.figma.ts</code> is intentionally not created until a Figma node URL exists; Code Connect publishing requires a real node.)</em></p><hr><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><p><a href="https://flowbite.com/docs/components/spinner/" target="_blank" rel="noreferrer"><code>https://flowbite.com/docs/components/spinner/</code></a> — adapted into the AI design system using existing status colour tokens and the icon-size scale.</p><h2 id="variant-matrix" tabindex="-1">Variant matrix <a class="header-anchor" href="#variant-matrix" aria-label="Permalink to &quot;Variant matrix&quot;">​</a></h2><p>Two independent axes:</p><table tabindex="0"><thead><tr><th>Axis</th><th>Values</th><th>CSS modifiers</th></tr></thead><tbody><tr><td>Size</td><td>sm · default · lg · xl</td><td><code>--sm</code> · (none) · <code>--lg</code> · <code>--xl</code></td></tr><tr><td>Colour</td><td>brand · success · warning · danger · info · neutral · inverted</td><td><code>--brand</code> · <code>--success</code> · <code>--warning</code> · <code>--danger</code> · <code>--info</code> · <code>--neutral</code> · <code>--inverted</code></td></tr></tbody></table><p>Total: 4 × 7 = 28 combinations. The CSS lets consumers also override <code>color</code> directly on the element (the ring inherits via <code>currentColor</code>) for one-off tinting.</p><h2 id="css-class-mapping" tabindex="-1">CSS class mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS class mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Class</th><th>Notes</th></tr></thead><tbody><tr><td>Wrapper</td><td><code>&lt;span class=&quot;spinner&quot; role=&quot;status&quot;&gt;</code></td><td>Outer rotating ring. <code>role=&quot;status&quot;</code> makes screen readers announce the loading state.</td></tr><tr><td>Visually-hidden label</td><td><code>&lt;span class=&quot;spinner__label&quot;&gt;Loading…&lt;/span&gt;</code></td><td>Text inside the wrapper for SR users. Optional — alternatively put <code>aria-label=&quot;Loading&quot;</code> on the wrapper.</td></tr><tr><td>Size modifier</td><td>`.spinner--{sm</td><td>lg</td></tr><tr><td>Colour modifier</td><td>`.spinner--{brand</td><td>success</td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Default diameter</td><td><code>--ai-icon-size-md</code> (20px)</td></tr><tr><td>sm diameter</td><td><code>--ai-icon-size-sm</code> (16px)</td></tr><tr><td>lg diameter</td><td><code>--ai-icon-size-lg</code> (24px)</td></tr><tr><td>xl diameter</td><td><code>--ai-icon-size-xl</code> (32px)</td></tr><tr><td>Border radius</td><td><code>--ai-radius-full</code></td></tr><tr><td>Brand colour</td><td><code>--ai-surface-brand</code></td></tr><tr><td>Success</td><td><code>--ai-surface-success</code></td></tr><tr><td>Warning</td><td><code>--ai-surface-warning</code></td></tr><tr><td>Danger</td><td><code>--ai-surface-error</code></td></tr><tr><td>Info</td><td><code>--ai-surface-info</code></td></tr><tr><td>Neutral</td><td><code>--ai-text-contrast</code></td></tr><tr><td>Inverted</td><td><code>--ai-btn-primary-text</code> (white in light + dark)</td></tr></tbody></table><p>Border widths: 2px / 2px / 3px / 4px for sm / default / lg / xl. Optical pixel values, kept as <code>px</code> per project rule (border-widths are not tokenised).</p><h2 id="animation" tabindex="-1">Animation <a class="header-anchor" href="#animation" aria-label="Permalink to &quot;Animation&quot;">​</a></h2><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@keyframes</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> ai-spinner-spin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  to</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">transform</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rotate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">360</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">deg</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">); }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Duration <code>750ms</code>, <code>linear</code>, <code>infinite</code>. Single keyframe rotation.</p><p><code>prefers-reduced-motion: reduce</code> pauses the animation — the ring is shown statically (still visible as a ring with a leading arc, just not spinning).</p><h2 id="track-effect" tabindex="-1">Track effect <a class="header-anchor" href="#track-effect" aria-label="Permalink to &quot;Track effect&quot;">​</a></h2><p>The &quot;rest of the ring&quot; is rendered as <code>currentColor</code> at 20% opacity using <code>color-mix()</code>:</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">border-color</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: color-mix(in srgb, currentColor 20%, transparent);</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">border-top-color</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: currentColor;</span></span></code></pre></div><p>This produces a faded full ring with a solid leading arc (mimicking Flowbite&#39;s track + arc SVG) using a single border declaration. <code>color-mix()</code> is supported in all evergreen browsers (Chrome 111+, Firefox 113+, Safari 16.2+).</p><h2 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h2><ul><li><code>role=&quot;status&quot;</code> on the wrapper — screen readers announce content changes inside the role-status region.</li><li>A textual label MUST be provided, either via <code>&lt;span class=&quot;spinner__label&quot;&gt;Loading…&lt;/span&gt;</code> (visually hidden) inside the wrapper, OR via <code>aria-label=&quot;Loading&quot;</code> on the wrapper.</li><li>When the spinner is inside a button that&#39;s processing, also set <code>aria-busy=&quot;true&quot;</code> and <code>disabled</code> on the button. The icon itself can carry <code>aria-hidden=&quot;true&quot;</code> because the button context already conveys the busy state.</li><li><code>prefers-reduced-motion: reduce</code> honoured.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><p>None — pure CSS, no JS, no other DS components required.</p><h2 id="composition-examples-in-spinner-html" tabindex="-1">Composition examples (in <code>Spinner.html</code>) <a class="header-anchor" href="#composition-examples-in-spinner-html" aria-label="Permalink to &quot;Composition examples (in `Spinner.html`)&quot;">​</a></h2><ul><li><strong>Sizes</strong> — sm / default / lg / xl side by side</li><li><strong>Status colours</strong> — all 6 named colours at lg</li><li><strong>With status text</strong> — inline spinner + &quot;Loading…&quot; label</li><li><strong>Inside a button</strong> — <code>&lt;button disabled aria-busy=&quot;true&quot;&gt;</code> with <code>.spinner--sm</code> + label text. Primary/Alert use <code>--inverted</code> (white spinner); Secondary uses <code>--brand</code>.</li><li><strong>Inverted on a coloured surface</strong> — white spinner on a <code>--ai-surface-brand</code> panel</li><li><strong>Centred</strong> — placeholder for page/section loading (<code>min-height: 8rem</code> panel with the xl spinner centred)</li></ul><h2 id="outstanding" tabindex="-1">Outstanding <a class="header-anchor" href="#outstanding" aria-label="Permalink to &quot;Outstanding&quot;">​</a></h2><ul><li><strong>No Figma source yet.</strong> Designer should formalise this as a Figma component (Size × Colour axes) — see the variant matrix above for the suggested structure. Once designed, re-build via <code>/build-component</code> and reconcile any visual differences. Push the <code>Spinner.html</code> demo to Figma immediately after build so the designer has a starting point.</li></ul>',30)])])}const g=t(o,[["render",s]]);export{u as __pageData,g as default};
